import poledb as PDB
import os
from tqdm import tqdm 
import shutil
import json
import matplotlib.pyplot as plt

global in_num
global out_num
    
def pole_Info(poleid):
    global in_num
    global out_num
    global re_out
    global re_in
    pole_sgn_count=PDB.get_meas_result_count(poleid)
    re_out=PDB.get_meas_result(poleid, 'OUT')
    num_sig_out=re_out.shape[0]
    re_in=PDB.get_meas_result(poleid, 'IN')
    num_sig_in=re_in.shape[0]
    in_num = num_sig_in
    out_num = num_sig_out
        
    return num_sig_out,num_sig_in,re_out,re_in
    
#====================================================================
# csv 파일 만들기
#====================================================================
def make_csv():
    normal_file = 'raw_data_ai_csv/normal/'
    break_file = 'raw_data_ai_csv/break/'
    new_csv_set = 0
    
    if not os.path.exists(normal_file):
        os.makedirs(normal_file)
        
    if not os.path.exists(break_file):
        os.makedirs(break_file)
        
    server_list = ["main", "is", "kh"]
    for server in server_list:
        PDB.poledb_init(server)
        print(server + "서버 // 데이터 수집중")
        groupname_list = PDB.groupname_info()
        total_num = len(groupname_list)
        group_num = 0
        for i in groupname_list:
            try:
                normal_file_path = "raw_data_ai_json\\normal\\" + i +".json"
                break_file_path = "raw_data_ai_json\\break\\" + i +".json"
                normal_new_data = 0
                break_new_data = 0
                
                with open(normal_file_path, 'r', encoding='utf-8') as json_file:
                    normal_data = json.load(json_file)
                with open(break_file_path, 'r', encoding='utf-8') as json_file:
                    break_data = json.load(json_file)
                    
                Pole_list = PDB.get_pole_list(i)
                
                print("")
                print(server + "서버 // " + str(round((group_num*100/total_num), 2)) + "% // " + i +  "원본데이터 확인중")
                if not Pole_list.empty :
                    if not os.path.exists(f"{normal_file}{i}"):
                        os.makedirs(normal_file + i)
                    if not os.path.exists(f"{break_file}{i}"):
                        os.makedirs(break_file + i)
                    
                    normal_name_list = []
                    normal_file_list = ([f for f in os.listdir(normal_file + i) if os.path.isfile(os.path.join(normal_file + i, f))])
                    for nn in normal_file_list:
                        normal_name_list.append((nn.split('_'))[0])
                    
                    break_name_list = []
                    break_file_list = ([f for f in os.listdir(break_file + i) if os.path.isfile(os.path.join(break_file + i, f))])
                    for nn in break_file_list:
                        break_name_list.append((nn.split('_'))[0])
                    
                    total_name_list = normal_name_list + break_name_list
                    total_name_list = list(set(total_name_list))
                    need_pole_list = list(set(list(Pole_list['poleid'])) - set(total_name_list))
                    
                    if len(need_pole_list) > 0: 
                        for poleid in tqdm(Pole_list['poleid'], desc="Processing poles"):
                            if poleid in need_pole_list:
                                if not normal_data == [] :
                                    for ii in normal_data:
                                        if poleid == ii:
                                            poleinfo = pole_Info(poleid)
                                            for kk in range(out_num):
                                                stype = 'OUT'
                                                num = int(re_out['measno'][kk])
                                                time = str(re_out['sttime'][kk])
                                                time = (time.split(" "))[0]
                                                
                                                stdegree = str(re_out['stdegree'][kk])
                                                eddegree = str(re_out['eddegree'][kk])
                                                stheight = str(re_out['stheight'][kk])
                                                edheight = str(re_out['edheight'][kk])
                                                        
                                                if not os.path.exists(f"{normal_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_x.csv"):
                                                    out_x = PDB.get_meas_data(poleid, num, stype, 'x')
                                                    out_x.to_csv(os.path.join(normal_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_x.csv"), index=False)
                                                    normal_new_data = normal_new_data + 1
                                                    
                                                if not os.path.exists(f"{normal_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_y.csv"):
                                                    out_y = PDB.get_meas_data(poleid, num, stype, 'y')
                                                    out_y.to_csv(os.path.join(normal_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_y.csv"), index=False)
                                                    normal_new_data = normal_new_data + 1
                                                    
                                                if not os.path.exists(f"{normal_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_z.csv"):
                                                    out_z = PDB.get_meas_data(poleid, num, stype, 'z')
                                                    out_z.to_csv(os.path.join(normal_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_z.csv"), index=False)
                                                    normal_new_data = normal_new_data + 1
                                                    
                                if not break_data == []:
                                    for jj in break_data:
                                        if poleid == jj[0]:
                                            poleinfo = pole_Info(poleid)
                                            for kk in range(out_num):
                                                stype = 'OUT'                          
                                                num = int(re_out['measno'][kk])                                  
                                                time = str(re_out['sttime'][kk])
                                                time = (time.split(" "))[0]
                                                
                                                stdegree = str(re_out['stdegree'][kk])
                                                eddegree = str(re_out['eddegree'][kk])
                                                stheight = str(re_out['stheight'][kk])
                                                edheight = str(re_out['edheight'][kk])
                                                if float(stdegree) <= float(jj[2]) <= float(eddegree) and float(stheight) <= float(jj[1]) <= float(edheight):
                                                    if not os.path.exists(f"{break_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_x.csv"):
                                                        out_x = PDB.get_meas_data(poleid, num, stype, 'x')
                                                        out_x.to_csv(os.path.join(break_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_x.csv"), index=False)
                                                        break_new_data = break_new_data + 1
                                                        
                                                    if not os.path.exists(f"{break_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_y.csv"):
                                                        out_y = PDB.get_meas_data(poleid, num, stype, 'y')
                                                        out_y.to_csv(os.path.join(break_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_y.csv"), index=False)
                                                        break_new_data = break_new_data + 1
                                                        
                                                    if not os.path.exists(f"{break_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_z.csv"):
                                                        out_z = PDB.get_meas_data(poleid, num, stype, 'z')
                                                        out_z.to_csv(os.path.join(break_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_z.csv"), index=False)
                                                        break_new_data = break_new_data + 1
                                                        
                                                else:
                                                    if not os.path.exists(f"{normal_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_x.csv"):
                                                        out_x = PDB.get_meas_data(poleid, num, stype, 'x')
                                                        out_x.to_csv(os.path.join(normal_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_x.csv"), index=False)
                                                        normal_new_data = normal_new_data + 1
                                                        
                                                    if not os.path.exists(f"{normal_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_y.csv"):
                                                        out_y = PDB.get_meas_data(poleid, num, stype, 'y')
                                                        out_y.to_csv(os.path.join(normal_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_y.csv"), index=False)
                                                        normal_new_data = normal_new_data + 1
                                                        
                                                    if not os.path.exists(f"{normal_file}{i}/{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_z.csv"):
                                                        out_z = PDB.get_meas_data(poleid, num, stype, 'z')
                                                        out_z.to_csv(os.path.join(normal_file + i, f"{poleid}_{kk+1}_{time}_{stdegree}_{eddegree}_{stheight}_{edheight}_H_z.csv"), index=False)
                                                        normal_new_data = normal_new_data + 1
                                                
                group_num = group_num + 1                     
                #print(server + "서버 // " + str(round((group_num*100/total_num), 2)) + "% // " + i +  "원본데이터 확인중")
                print("새로 추가된 파일 // 정상 " + str(normal_new_data) + "개 / 파단 " + str(break_new_data) + "개")
                print("")
            except Exception as e:
                print("오류발생: ", e)
                
    print("원본데이터 추출완료 // ")
                                    
#==================================================================== 
# csv 파일 만들기
#====================================================================
make_csv()    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          